// src/lib/tripay.ts
import crypto3 from "crypto";
async function getTripayConfig() {
  try {
    const settingRow = await db.query.systemSettings.findFirst({
      where: eq(systemSettings.key, "tripay")
    });
    if (!settingRow || !settingRow.value)
      return null;
    const config = settingRow.value;
    if (config.apiKey && config.privateKey && config.merchantCode) {
      return {
        apiKey: config.apiKey,
        privateKey: config.privateKey,
        merchantCode: config.merchantCode,
        isSandbox: config.isSandbox !== false
      };
    }
  } catch (error) {
    console.error("Error fetching Tripay settings:", error);
  }
  return null;
}
async function createTripayTransaction(params) {
  const config = await getTripayConfig();
  if (!config) {
    console.log("Tripay not configured. Simulating payment gateway transaction...");
    const isQris = params.method === "QRIS";
    const expiredTime = Math.floor(Date.now() / 1000) + 24 * 3600;
    const mockRef = "TRX-" + Math.random().toString(36).substring(2, 11).toUpperCase();
    return {
      reference: mockRef,
      merchant_ref: params.merchantRef,
      payment_name: isQris ? "QRIS (Simulasi)" : `${params.method} Virtual Account (Simulasi)`,
      payment_method: params.method,
      payment_code: isQris ? "NgaturiSimulatedQRIS" : "88301" + Math.floor(1e7 + Math.random() * 90000000),
      qr_url: isQris ? `https://api.qrserver.com/v1/create-qr-code/?size=300x300&data=NgaturiPayment-${params.merchantRef}` : undefined,
      amount: params.amount,
      status: "UNPAID",
      expired_time: expiredTime,
      instructions: [
        {
          title: "Cara Pembayaran via ATM",
          steps: [
            "Masukkan kartu ATM dan PIN Anda.",
            "Pilih menu Transaksi Lainnya > Transfer > Ke Rekening Virtual Account.",
            `Masukkan Kode Bayar: ${isQris ? "Scan QR Code" : "Nomor VA di atas"}.`,
            `Pastikan nominal transfer sama dengan ${new Intl.NumberFormat("id-ID", { style: "currency", currency: "IDR", minimumFractionDigits: 0 }).format(params.amount)}.`,
            "Ikuti instruksi selanjutnya untuk menyelesaikan transaksi."
          ]
        },
        {
          title: "Cara Pembayaran via M-Banking",
          steps: [
            "Buka aplikasi Mobile Banking Anda.",
            "Pilih menu Transfer > Virtual Account.",
            `Input Nomor Virtual Account / Kode Bayar.`,
            "Periksa detail tagihan, lalu konfirmasi pembayaran.",
            "Masukkan PIN M-Banking Anda."
          ]
        }
      ]
    };
  }
  const { apiKey, privateKey, merchantCode, isSandbox } = config;
  const baseUrl = isSandbox ? "https://tripay.co.id/api-sandbox/transaction/create" : "https://tripay.co.id/api/transaction/create";
  const signature = crypto3.createHmac("sha256", privateKey).update(merchantCode + params.merchantRef + params.amount).digest("hex");
  const callbackUrl = process.env.API_URL ? `${process.env.API_URL}/api/webhook/payment` : "http://localhost:4000/api/webhook/payment";
  const body = {
    method: params.method,
    merchant_ref: params.merchantRef,
    amount: params.amount,
    customer_name: params.customerName,
    customer_email: params.customerEmail,
    order_items: [
      {
        name: params.packageName,
        price: params.amount,
        quantity: 1
      }
    ],
    callback_url: callbackUrl,
    expired_time: Math.floor(Date.now() / 1000) + 24 * 3600,
    signature
  };
  try {
    const response = await fetch(baseUrl, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        Authorization: `Bearer ${apiKey}`
      },
      body: JSON.stringify(body)
    });
    const result2 = await response.json();
    if (!response.ok || !result2.success) {
      throw new Error(result2.message || "Gagal membuat transaksi di Tripay.");
    }
    return result2.data;
  } catch (error) {
    console.error("Tripay Request Failure:", error);
    throw new Error(error.message || "Gagal menghubungi server Tripay.");
  }
}

// src/routes/orders.ts
var ordersRouter = new Hono2;
ordersRouter.use("*", requireAuth);
ordersRouter.get("/packages", async (c) => {
  try {
    const list = await db.query.packages.findMany();
    return c.json({ status: "success", packages: list });
  } catch (error) {
    console.error("Error fetching packages:", error);
    return c.json({ status: "error", message: "Gagal mengambil paket." }, 500);
  }
});
ordersRouter.get("/history", async (c) => {
  const user = c.get("user");
  try {
    const list = await db.select({
      id: orders.id,
      status: orders.status,
      amount: orders.amount,
      paymentMethod: orders.paymentMethod,
      paidAt: orders.paidAt,
      createdAt: orders.createdAt,
      packageName: packages.name
    }).from(orders).leftJoin(packages, eq(orders.packageId, packages.id)).where(eq(orders.userId, user.id)).orderBy(desc(orders.createdAt));
    return c.json({ status: "success", history: list });
  } catch (error) {
    console.error("Error fetching order history:", error);
    return c.json({ status: "error", message: "Gagal mengambil riwayat transaksi." }, 500);
  }
});
ordersRouter.get("/:id", async (c) => {
  const user = c.get("user");
  const orderId = c.req.param("id");
  try {
    const list = await db.select({
      id: orders.id,
      status: orders.status,
      amount: orders.amount,
      paymentMethod: orders.paymentMethod,
      paidAt: orders.paidAt,
      createdAt: orders.createdAt,
      packageName: packages.name
    }).from(orders).leftJoin(packages, eq(orders.packageId, packages.id)).where(and(eq(orders.id, orderId), eq(orders.userId, user.id))).limit(1);
    if (list.length === 0) {
      return c.json({ status: "error", message: "Order tidak ditemukan." }, 404);
    }
    const transaction = await db.query.transactions.findFirst({
      where: eq(transactions.orderId, orderId),
      orderBy: desc(transactions.createdAt)
    });
    return c.json({ status: "success", order: list[0], transaction });
  } catch (error) {
    console.error("Error fetching order detail:", error);
    return c.json({ status: "error", message: "Gagal memuat detail order." }, 500);
  }
});
ordersRouter.post("/checkout", async (c) => {
  const user = c.get("user");
  try {
    const { packageId, paymentMethod } = await c.req.json();
    if (!packageId || !paymentMethod) {
      return c.json({ status: "error", message: "ID Paket dan Metode Pembayaran wajib diisi." }, 400);
    }
    const pkg = await db.query.packages.findFirst({
      where: eq(packages.id, packageId)
    });
    if (!pkg) {
      return c.json({ status: "error", message: "Paket tidak ditemukan." }, 400);
    }
    const [newOrder] = await db.insert(orders).values({
      userId: user.id,
      packageId: pkg.id,
      status: "PENDING",
      amount: pkg.price,
      paymentMethod
    }).returning();
    let tripayTrx;
    try {
      tripayTrx = await createTripayTransaction({
        method: paymentMethod,
        merchantRef: newOrder.id,
        amount: pkg.price,
        customerName: user.name,
        customerEmail: user.email,
        packageName: pkg.name
      });
    } catch (apiErr) {
      await db.delete(orders).where(eq(orders.id, newOrder.id));
      return c.json({ status: "error", message: apiErr.message || "Gagal mendaftarkan tagihan ke payment gateway." }, 400);
    }
    await db.insert(transactions).values({
      orderId: newOrder.id,
      gatewayRef: tripayTrx.reference,
      status: "pending",
      payload: tripayTrx
    });
    try {
      await sendOrderCreated(user.email, user.name, newOrder.id, newOrder.amount, pkg.name, tripayTrx.payment_name || paymentMethod, tripayTrx.payment_code, tripayTrx.qr_url);
    } catch (mailErr) {
      console.error("[Mail Error] Failed to send order confirmation email to customer:", mailErr);
    }
    try {
      const admins = await db.select().from(users).where(eq(users.role, "ADMIN"));
      for (const admin of admins) {
        try {
          await sendAdminOrderNotification(admin.email, newOrder.id, newOrder.amount, pkg.name, user.name, user.email);
        } catch (adminMailErr) {
          console.error(`[Mail Error] Failed to notify admin ${admin.email}:`, adminMailErr);
        }
      }
    } catch (adminErr) {
      console.error("[Admin Query Error] Failed to fetch admins for order notification:", adminErr);
    }
    return c.json({
      status: "success",
      message: "Transaksi berhasil didaftarkan.",
      order: newOrder,
      tripay: tripayTrx
    });
  } catch (error) {
    console.error("Checkout error:", error);
    return c.json({ status: "error", message: "Gagal memproses pembayaran." }, 500);
  }
});
