guestsRouter.get("/stats", async (c) => {
  const user = c.get("user");
  try {
    const wedding = await db.query.weddings.findFirst({
      where: eq(weddings.userId, user.id)
    });
    if (!wedding) {
      return c.json({
        status: "success",
        stats: { total: 0, attending: 0, declined: 0, tentative: 0, pending: 0 }
      });
    }
    const stats = await db.select({
      status: guests.rsvpStatus,
      count: sql`count(${guests.id})::int`
    }).from(guests).where(eq(guests.weddingId, wedding.id)).groupBy(guests.rsvpStatus);
    const result2 = {
      total: 0,
      attending: 0,
      declined: 0,
      tentative: 0,
      pending: 0
    };
    stats.forEach((row) => {
      const count2 = row.count || 0;
      result2.total += count2;
      if (row.status === "attending" || row.status === "hadir") {
        result2.attending += count2;
      } else if (row.status === "declined" || row.status === "tidak hadir") {
        result2.declined += count2;
      } else if (row.status === "tentative" || row.status === "ragu-ragu") {
        result2.tentative += count2;
      } else {
        result2.pending += count2;
      }
    });
    return c.json({ status: "success", stats: result2 });
  } catch (error) {
    console.error("Error fetching guest stats:", error);
    return c.json({ status: "error", message: "Gagal mengambil statistik tamu." }, 500);
  }
});
