async function cancelExpiredOrders() {
  try {
    const limitDate = new Date;
    limitDate.setHours(limitDate.getHours() - 24);
    const result2 = await db.update(orders).set({ status: "EXPIRED" }).where(and(eq(orders.status, "PENDING"), lt(orders.createdAt, limitDate))).returning({ id: orders.id });
    if (result2.length > 0) {
      console.log(`[Cron] Cancelled ${result2.length} pending orders that exceeded 24 hours.`);
      for (const ord of result2) {
        await db.update(transactions).set({ status: "failed" }).where(eq(transactions.orderId, ord.id));
      }
    }
  } catch (err) {
    console.error("Error in cron job cancelExpiredOrders:", err);
  }
}
cancelExpiredOrders();
setInterval(cancelExpiredOrders, 10 * 60 * 1000);
async function checkExpirationWarnings() {
  try {
    const now = new Date;
    const sevenDaysFromNow = new Date;
    sevenDaysFromNow.setDate(sevenDaysFromNow.getDate() + 7);
    const list = await db.select({
      weddingId: weddings.id,
      slug: weddings.slug,
      expiredAt: weddings.expiredAt,
      userName: users.name,
      userEmail: users.email,
      weddingData: weddings.data
    }).from(weddings).innerJoin(users, eq(weddings.userId, users.id)).where(and(eq(weddings.status, "published"), isNull(weddings.expirationWarningSentAt), gt(weddings.expiredAt, now), lt(weddings.expiredAt, sevenDaysFromNow)));
    for (const item of list) {
      if (!item.expiredAt)
        continue;
      const title = item.weddingData?.title || `Undangan /u/${item.slug}`;
      const dateStr = new Date(item.expiredAt).toLocaleDateString("id-ID", {
        weekday: "long",
        year: "numeric",
        month: "long",
        day: "numeric",
        hour: "2-digit",
        minute: "2-digit"
      });
      console.log(`[Cron Expiration] Sending 7-day warning for wedding /u/${item.slug} to ${item.userEmail}`);
      try {
        await sendExpirationWarning(item.userEmail, item.userName, title, dateStr);
        await db.update(weddings).set({ expirationWarningSentAt: new Date }).where(eq(weddings.id, item.weddingId));
      } catch (mailErr) {
        console.error(`[Cron Expiration Error] Failed to send email to ${item.userEmail}:`, mailErr);
      }
    }
  } catch (err) {
    console.error("Error in cron job checkExpirationWarnings:", err);
  }
}
checkExpirationWarnings();
setInterval(checkExpirationWarnings, 12 * 60 * 60 * 1000);
